pub async fn insert_user(pool: &sqlx::PgPool, name: &str, email: &str) -> Result<(), sqlx::Error> {
    sqlx::query!("INSERT INTO users (name, email) VALUES ($1, $2)", name, email)
        .execute(pool)
        .await?;
    Ok(())
}

